-- Consider the expression $(1 + \sqrt{8})^{2n+1} = a + b\sqrt{8}$, where $a$ and $b$ are integers.
set a := ∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k) * 8 ^ k
set b := ∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k + 1) * 8 ^ k;
-- Then $(1 + \sqrt{8})^{2n+1} = a + b\sqrt{8}$ and $(1 - \sqrt{8})^{2n+1} = a - b\sqrt{8}$.
have h1 : (1 + Real.sqrt 8)^(2 * n + 1) = a + b * Real.sqrt 8 := by
  rw [ add_comm, add_pow ];
  -- Separate the sum into two parts: one with even indices and one with odd indices.
  have h_split : Finset.range (2 * n + 2) = Finset.image (fun k => 2 * k) (Finset.range (n + 1)) ∪ Finset.image (fun k => 2 * k + 1) (Finset.range (n + 1)) := by
    ext k
    simp [Finset.mem_range, Finset.mem_image];
    exact ⟨ fun h => by rcases Nat.even_or_odd' k with ⟨ k, rfl | rfl ⟩ <;> [ left; right ] <;> exact ⟨ k, by linarith, rfl ⟩, fun h => by rcases h with ( ⟨ k, hk, rfl ⟩ | ⟨ k, hk, rfl ⟩ ) <;> linarith ⟩;
  rw [ h_split, Finset.sum_union ] <;> norm_num [ Finset.sum_mul _ _ _ ] ; ring;
  · norm_num +zetaDelta at *;
    norm_num [ pow_mul', mul_assoc, mul_comm, mul_left_comm, add_comm, add_left_comm, Finset.mul_sum _ _ _ ];
  · norm_num [ Finset.disjoint_right ];
    intros; omega;
have h2 : (1 - Real.sqrt 8)^(2 * n + 1) = a - b * Real.sqrt 8 := by
  -- By the binomial theorem, we have $(1 - \sqrt{8})^{2n+1} = \sum_{k=0}^{2n+1} \binom{2n+1}{k} (-\sqrt{8})^k$.
  have h_binom : (1 - Real.sqrt 8)^(2 * n + 1) = ∑ k ∈ Finset.range (2 * n + 2), Nat.choose (2 * n + 1) k * (-Real.sqrt 8)^k := by
    simp +decide [ sub_eq_neg_add, add_pow, mul_comm ];
  -- Let's separate the sum into two parts: one for even $k$ and one for odd $k$.
  have h_split : ∑ k ∈ Finset.range (2 * n + 2), Nat.choose (2 * n + 1) k * (-Real.sqrt 8)^k = (∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k) * (-Real.sqrt 8)^(2 * k)) + (∑ k ∈ Finset.range (n + 1), Nat.choose (2 * n + 1) (2 * k + 1) * (-Real.sqrt 8)^(2 * k + 1)) := by
    have h_split : Finset.range (2 * n + 2) = Finset.image (fun k => 2 * k) (Finset.range (n + 1)) ∪ Finset.image (fun k => 2 * k + 1) (Finset.range (n + 1)) := by
      ext k
      simp [Finset.mem_range, Finset.mem_image];
      exact ⟨ fun h => by rcases Nat.even_or_odd' k with ⟨ k, rfl | rfl ⟩ <;> [ left; right ] <;> exact ⟨ k, by linarith, rfl ⟩, fun h => by rcases h with ( ⟨ k, hk, rfl ⟩ | ⟨ k, hk, rfl ⟩ ) <;> linarith ⟩;
    rw [ h_split, Finset.sum_union ] <;> norm_num [ Finset.disjoint_right ];
    intros; omega;
  simp +zetaDelta at *;
  norm_num [ pow_add, pow_mul, h_binom, h_split ] ; ring;
  simp +decide only [mul_assoc, Finset.mul_sum _ _ _, mul_left_comm];
-- Multiplying these two equations, we get $(1 + \sqrt{8})^{2n+1}(1 - \sqrt{8})^{2n+1} = (a + b\sqrt{8})(a - b\sqrt{8}) = a^2 - 8b^2$.
have h3 : (1 + Real.sqrt 8)^(2 * n + 1) * (1 - Real.sqrt 8)^(2 * n + 1) = a^2 - 8 * b^2 := by
  rw [ h1, h2 ] ; ring ; norm_num;
-- Since $(1 + \sqrt{8})^{2n+1}(1 - \sqrt{8})^{2n+1} = (-7)^{2n+1}$, we have $a^2 - 8b^2 = (-7)^{2n+1}$.
have h4 : (a : ℝ)^2 - 8 * (b : ℝ)^2 = (-7 : ℝ)^(2 * n + 1) := by
  rw [ ← h3, ← mul_pow ] ; ring ; norm_num;
  ring;
norm_cast at *;
rw [ Int.subNatNat_eq_coe ] at h4 ; replace h4 := congr_arg ( · % 5 ) h4 ; norm_num [ pow_add, pow_mul, Int.add_emod, Int.sub_emod, Int.mul_emod ] at h4 ⊢ ; norm_cast at * ; simp_all +decide [ Nat.dvd_iff_mod_eq_zero ] ;
norm_num [ Nat.pow_mod, Nat.mul_mod ] at h4; have := Nat.mod_lt a ( by decide : 5 > 0 ) ; have := Nat.mod_lt b ( by decide : 5 > 0 ) ; interval_cases _ : a % 5 <;> interval_cases _ : b % 5 <;> simp_all +decide only [Int.subNatNat_eq_coe] ;
· norm_cast at h4; rw [ ← Nat.mod_add_div n 4 ] at h4; norm_num [ Nat.pow_add, Nat.pow_mul, Nat.mul_mod, Nat.pow_mod ] at h4; have := Nat.mod_lt n four_pos; interval_cases n % 4 <;> contradiction;
· norm_cast at h4; rw [ ← Nat.mod_add_div n 4 ] at h4; norm_num [ Nat.pow_add, Nat.pow_mul, Nat.mul_mod, Nat.pow_mod ] at h4; have := Nat.mod_lt n four_pos; interval_cases n % 4 <;> contradiction;
· norm_cast at h4; rw [ ← Nat.mod_add_div n 4 ] at h4; norm_num [ Nat.pow_add, Nat.pow_mul, Nat.mul_mod, Nat.pow_mod ] at h4; have := Nat.mod_lt n four_pos; interval_cases n % 4 <;> contradiction;
· norm_cast at h4; rw [ ← Nat.mod_add_div n 4 ] at h4; norm_num [ Nat.pow_add, Nat.pow_mul, Nat.mul_mod, Nat.pow_mod ] at h4; have := Nat.mod_lt n four_pos; interval_cases n % 4 <;> contradiction;
· norm_cast at h4; rw [ ← Nat.mod_add_div n 4 ] at h4; norm_num [ Nat.pow_add, Nat.pow_mul, Nat.mul_mod, Nat.pow_mod ] at h4; have := Nat.mod_lt n four_pos; interval_cases n % 4 <;> contradiction;

